))

(declare hydra_encode_error_checking_incorrect_unification_error hydra_encode_error_checking_not_a_forall_type_error hydra_encode_error_checking_not_a_function_type_error hydra_encode_error_checking_type_arity_mismatch_error hydra_encode_error_checking_type_mismatch_error hydra_encode_error_checking_unbound_type_variables_error hydra_encode_error_checking_unequal_types_error hydra_encode_error_checking_unsupported_term_variant_error hydra_encode_error_checking_untyped_lambda_error hydra_encode_error_checking_untyped_let_binding_error hydra_encode_error_checking_checking_error)

(def hydra_encode_error_checking_incorrect_unification_error (fn [x] (list :record (->hydra_core_record "hydra.error.checking.IncorrectUnificationError" (list (->hydra_core_field "substitution" (hydra_encode_typing_type_subst ((fn [v] (:substitution v)) x))))))))

(def hydra_encode_error_checking_not_a_forall_type_error (fn [x] (list :record (->hydra_core_record "hydra.error.checking.NotAForallTypeError" (list (->hydra_core_field "type" (hydra_encode_core_type ((fn [v] (:type v)) x))) (->hydra_core_field "typeArguments" ((fn [xs] (list :list ((hydra_lib_lists_map hydra_encode_core_type) xs))) ((fn [v] (:type_arguments v)) x))))))))

(def hydra_encode_error_checking_not_a_function_type_error (fn [x] (list :record (->hydra_core_record "hydra.error.checking.NotAFunctionTypeError" (list (->hydra_core_field "type" (hydra_encode_core_type ((fn [v] (:type v)) x))))))))

(def hydra_encode_error_checking_type_arity_mismatch_error (fn [x] (list :record (->hydra_core_record "hydra.error.checking.TypeArityMismatchError" (list (->hydra_core_field "type" (hydra_encode_core_type ((fn [v] (:type v)) x))) (->hydra_core_field "expectedArity" ((fn [x] (list :literal (list :integer (list :int32 x)))) ((fn [v] (:expected_arity v)) x))) (->hydra_core_field "actualArity" ((fn [x] (list :literal (list :integer (list :int32 x)))) ((fn [v] (:actual_arity v)) x))) (->hydra_core_field "typeArguments" ((fn [xs] (list :list ((hydra_lib_lists_map hydra_encode_core_type) xs))) ((fn [v] (:type_arguments v)) x))))))))

