(def hydra_encode_error_checking_unbound_type_variables_error (fn [x] (list :record (->hydra_core_record "hydra.error.checking.UnboundTypeVariablesError" (list (->hydra_core_field "variables" ((fn [s] (list :set ((hydra_lib_sets_map hydra_encode_core_name) s))) ((fn [v] (:variables v)) x))) (->hydra_core_field "type" (hydra_encode_core_type ((fn [v] (:type v)) x))))))))

(def hydra_encode_error_checking_unequal_types_error (fn [x] (list :record (->hydra_core_record "hydra.error.checking.UnequalTypesError" (list (->hydra_core_field "types" ((fn [xs] (list :list ((hydra_lib_lists_map hydra_encode_core_type) xs))) ((fn [v] (:types v)) x))) (->hydra_core_field "description" ((fn [x] (list :literal (list :string x))) ((fn [v] (:description v)) x))))))))

