(def hydra_encode_error_checking_untyped_lambda_error (fn [x] (list :record (->hydra_core_record "hydra.error.checking.UntypedLambdaError" (list)))))

(def hydra_encode_error_checking_untyped_let_binding_error (fn [x] (list :record (->hydra_core_record "hydra.error.checking.UntypedLetBindingError" (list (->hydra_core_field "binding" (hydra_encode_core_binding ((fn [v] (:binding v)) x))))))))

(def hydra_encode_error_checking_checking_error (fn [match_target] ((fn [match_value] (cond (= (first match_target) :incorrect_unification) ((fn [y] (list :union (->hydra_core_injection "hydra.error.checking.CheckingError" (->hydra_core_field "incorrectUnification" (hydra_encode_error_checking_incorrect_unification_error y))))) match_value) (= (first match_target) :not_a_forall_type) ((fn [y] (list :union (->hydra_core_injection "hydra.error.checking.CheckingError" (->hydra_core_field "notAForallType" (hydra_encode_error_checking_not_a_forall_type_error y))))) match_value) (= (first match_target) :not_a_function_type) ((fn [y] (list :union (->hydra_core_injection "hydra.error.checking.CheckingError" (->hydra_core_field "notAFunctionType" (hydra_encode_error_checking_not_a_function_type_error y))))) match_value) (= (first match_target) :type_arity_mismatch) ((fn [y] (list :union (->hydra_core_injection "hydra.error.checking.CheckingError" (->hydra_core_field "typeArityMismatch" (hydra_encode_error_checking_type_arity_mismatch_error y))))) match_value) (= (first match_target) :type_mismatch) ((fn [y] (list :union (->hydra_core_injection "hydra.error.checking.CheckingError" (->hydra_core_field "typeMismatch" (hydra_encode_error_checking_type_mismatch_error y))))) match_value) (= (first match_target) :unbound_type_variables) ((fn [y] (list :union (->hydra_core_injection "hydra.error.checking.CheckingError" (->hydra_core_field "unboundTypeVariables" (hydra_encode_error_checking_unbound_type_variables_error y))))) match_value) (= (first match_target) :unequal_types) ((fn [y] (list :union (->hydra_core_injection "hydra.error.checking.CheckingError" (->hydra_core_field "unequalTypes" (hydra_encode_error_checking_unequal_types_error y))))) match_value) (= (first match_target) :unsupported_term_variant) ((fn [y] (list :union (->hydra_core_injection "hydra.error.checking.CheckingError" (->hydra_core_field "unsupportedTermVariant" (hydra_encode_error_checking_unsupported_term_variant_error y))))) match_value) (= (first match_target) :untyped_lambda) ((fn [y] (list :union (->hydra_core_injection "hydra.error.checking.CheckingError" (->hydra_core_field "untypedLambda" (hydra_encode_error_checking_untyped_lambda_error y))))) match_value) (= (first match_target) :untyped_let_binding) ((fn [y] (list :union (->hydra_core_injection "hydra.error.checking.CheckingError" (->hydra_core_field "untypedLetBinding" (hydra_encode_error_checking_untyped_let_binding_error y))))) match_value))) (second match_target))))
